// ============================================================================
// HEAD Reading Tests
// ============================================================================

TEST(integration_read_head) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // HEAD should NOT be detached (pointing to master branch)
    TEST_ASSERT_FALSE(repo.head_detached);
    // head_ref should be "master"
    TEST_ASSERT_STREQ(repo.head_ref, "master");

    git_repo_close(&repo);
}

TEST(integration_head_sha_valid) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // HEAD SHA should be exactly 40 hex characters
    TEST_ASSERT_EQ(strlen(repo.head_sha), 40);

    // Verify all characters are valid hex
    for (int i = 0; i < 40; i++) {
        char c = repo.head_sha[i];
        bool is_hex = (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f');
        TEST_ASSERT_TRUE(is_hex);
    }

    git_repo_close(&repo);
}

// ============================================================================
// Reference Listing Tests
// ============================================================================

TEST(integration_list_refs) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Pre-allocate buffer for refs
    GitRef refs[100];
    size_t ref_count = git_list_refs(&repo, refs, 100);

    TEST_ASSERT_TRUE(ref_count > 0);

    // Should have at least the master branch
    bool found_master = false;
    for (size_t i = 0; i < ref_count; i++) {
        if (strcmp(refs[i].name, "master") == 0) {
            found_master = true;
            break;
        }
    }
    TEST_ASSERT_TRUE(found_master);

    git_repo_close(&repo);
}

TEST(integration_refs_have_valid_shas) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    GitRef refs[100];
    size_t ref_count = git_list_refs(&repo, refs, 100);

    TEST_ASSERT_TRUE(ref_count > 0);

    for (size_t i = 0; i < ref_count; i++) {
        // Each ref SHA should be 40 hex characters
        TEST_ASSERT_EQ(strlen(refs[i].sha), 40);
    }

    git_repo_close(&repo);
}
